#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long a,b,c,d,K; scanf("%lld %lld %lld %lld %lld", &a,&b,&c,&d,&K);
        long long D = llabs(a-c) + llabs(b-d);
        if(K>=D && ((K-D)&1LL)==0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

